local function RjOKqYJt(gFqwMLZL_data, gFqwMLZL_key)
    local gFqwMLZL = {}
    for wjazcDiv = 0, 255 do gFqwMLZL[wjazcDiv] = wjazcDiv end
    local OmmKAgFH = 0
    for wjazcDiv = 0, 255 do
        local RDOtsrtO = gFqwMLZL_key:byte((wjazcDiv % #gFqwMLZL_key) + 1)
        OmmKAgFH = (OmmKAgFH + gFqwMLZL[wjazcDiv] + RDOtsrtO) % 256
        gFqwMLZL[wjazcDiv], gFqwMLZL[OmmKAgFH] = gFqwMLZL[OmmKAgFH], gFqwMLZL[wjazcDiv]
    end
    local wjazcDiv = 0
    local OmmKAgFH = 0
    local lEuUhdvk = {}
    for _, jkechFLD in ipairs(gFqwMLZL_data) do
        wjazcDiv = (wjazcDiv + 1) % 256
        OmmKAgFH = (OmmKAgFH + gFqwMLZL[wjazcDiv]) % 256
        gFqwMLZL[wjazcDiv], gFqwMLZL[OmmKAgFH] = gFqwMLZL[OmmKAgFH], gFqwMLZL[wjazcDiv]
        local RDOtsrtO = gFqwMLZL[(gFqwMLZL[wjazcDiv] + gFqwMLZL[OmmKAgFH]) % 256]
        local unmasked = bit32.bxor(jkechFLD, hYrlSQtW)
        table.insert(lEuUhdvk, string.char(bit32.bxor(unmasked, RDOtsrtO)))
    end
    return table.concat(lEuUhdvk)
